{
    "code": "ct_conso",
    "description": "Table des consommations",
    "disabled": false,
    "name": "ct_conso",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "exploitation",
            "description": "Exploitation",
            "fieldType": "STRING"
        },
        {
            "code": "num_contrat",
            "description": "N° Contrat",
            "fieldType": "STRING"
        },
        {
            "code": "lot",
            "description": "Lot",
            "fieldType": "LONG"
        },
        {
            "code": "tournee",
            "description": "Tournée",
            "fieldType": "LONG"
        },
        {
            "code": "nom_client",
            "description": "Nom client",
            "fieldType": "STRING"
        },
        {
            "code": "quantite",
            "description": "Quantité consommée",
            "fieldType": "STRING"
        },
        {
            "code": "unite",
            "description": "Unité de la consommation",
            "fieldType": "STRING"
        },
        {
            "code": "id_pds",
            "description": "Identifiant du point de service",
            "fieldType": "STRING"
        },
        {
            "code": "num_compteur",
            "description": "Numéro du compteur",
            "fieldType": "STRING"
        },
        {
            "code": "index_precedent",
            "description": "Index précédent",
            "fieldType": "STRING"
        },
        {
            "code": "index_nouveau",
            "description": "Index ayant permis le calcul de la consommation",
            "fieldType": "STRING"
        },
        {
            "code": "date_index_precedent",
            "description": "Date de la relève précédente",
            "fieldType": "DATE"
        },
        {
            "code": "date_releve",
            "description": "Date de la relève ayant permis le calcul de la consommation",
            "fieldType": "DATE"
        },
        {
            "code": "nature_releve",
            "description": "Nature de la relève",
            "fieldType": "LIST",
            "listValues": {
                "REEL": "REEL",
                "ESTIME": "ESTIME",
                "EVENEMENT": "EVENEMENT",
                "DEPOSE": "DEPOSE"
            }
        },
        {
            "code": "origine",
            "description": "Origine de la relève",
            "fieldType": "LIST",
            "listValues": {
                "MAREL": "MAREL",
                "SATURNE": "SATURNE",
                "SMARTSIDE": "SMARTSIDE",
                "ENERLAKE": "ENERLAKE",
                "ADVANCE": "ADVANCE",
                "DI": "DI",
                "AEL": "AEL",
                "TELEPHONE": "TELEPHONE",
                "MANUEL": "MANUEL",
                "OPENCELL": "OPENCELL"
            }
        },
        {
            "code": "poste_horosaisonnier",
            "description": "Poste horosaisonnier",
            "fieldType": "LIST",
            "listValues": {
                "BASE": "BASE",
                "HP": "HP",
                "HC": "HC",
                "JOUR": "JOUR",
                "NUIT": "NUIT"
            }
        },
        {
            "code": "nature_mesure",
            "description": "Nature de la mesure",
            "fieldType": "LIST",
            "listValues": {
                "EA": "EA",
                "ER": "ER",
                "EAi": "EAi",
                "ERi": "ERi",
                "Imax": "Imax",
                "PA": "PA",
                "DD": "DD",
                "VOL": "VOL",
                "VOLR": "VOLR",
                "COSPHI": "COSPHI",
                "DP": "DP"
            }
        },
        {
            "code": "edr_id",
            "description": "Identifiant de l’EDR associé à la consommation",
            "fieldType": "LONG"
        },
         {
            "code": "code_erreur",
            "description": "Code erreur",
            "fieldType": "STRING"
        },
        {
            "code": "calcul_HTA",
            "description": "flag sur la consommation HTA calculee",
            "fieldType": "BOOLEAN"
        },
        {
            "code": "message_erreur",
            "description": "Message erreur",
            "fieldType": "STRING",
            "maxValue": 200
        },
        {
            "code": "statut",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "IMPORTE": "IMPORTE",
                "VALORISE": "VALORISE",
                "CALCULE": "CALCULE",
                "INFO": "INFO",
                "ERREUR": "ERREUR"
            }
        }
    ],
    "action": []
}
